import React, { useState } from 'react';
import { Box, Button, TextField, Typography, MenuItem, FormControl, InputLabel, Select, Checkbox, FormControlLabel, FormGroup, Grid, CircularProgress, Paper } from '@mui/material';
import Navbar from '../components/Navbar';
import Footer from '../components/Footer';
import axiosInstance from '../utils/axiosInstance';
import { useSelector } from 'react-redux';

const FineTuningPage = () => {
    const allDatasets = useSelector(state => state.datasets.allDatasets);
    const [model, setModel] = useState('');
    const [customModel, setCustomModel] = useState('');
    const [finetunedModelName, setFinetunedModelName] = useState('');
    const [selectedDatasets, setSelectedDatasets] = useState([]);
    const [testSamples, setTestSamples] = useState('');
    const [userDataset, setUserDataset] = useState(null);
    const [hyperparameters, setHyperparameters] = useState({
        lora_alpha: 16,
        lora_dropout: 0.1,
        lora_r: 64,
        per_device_train_batch_size: 4,
        gradient_accumulation_steps: 1,
        optim: 'paged_adamw_32bit',
        save_steps: 200,
        logging_steps: 500,
        learning_rate: 1e-4,
        max_grad_norm: 0.3,
        max_steps: 10000,
        warmup_ratio: 0.05,
        lr_scheduler_type: 'cosine',
    });
    const [isLoading, setIsLoading] = useState(false);
    const [fineTuningStatus, setFineTuningStatus] = useState('');

    const handleModelChange = (event) => {
        setModel(event.target.value);
    };

    const handleDatasetChange = (event) => {
        const { name, checked } = event.target;
        if (checked) {
            const dataset = allDatasets.flatMap(group => group.datasets).find(d => d.id === name);
            setSelectedDatasets([...selectedDatasets, dataset.fileUrl]);
        } else {
            setSelectedDatasets(selectedDatasets.filter(url => url !== name));
        }
    };

    const handleHyperparameterChange = (event) => {
        setHyperparameters({
            ...hyperparameters,
            [event.target.name]: event.target.value,
        });
    };

    const handleUserDatasetChange = (event) => {
        setUserDataset(event.target.files[0]);
    };

    const handleStartFineTuning = () => {
        setIsLoading(true);

        const formData = new FormData();
        formData.append('model_id', model === 'Other' ? customModel : model);
        formData.append('finetuned_model_name', finetunedModelName);
        formData.append('datasets', JSON.stringify(selectedDatasets));
        formData.append('test_samples', testSamples);
        formData.append('hyperparameters', JSON.stringify(hyperparameters));
        if (userDataset) {
            formData.append('user_dataset', userDataset);
        }

        axiosInstance.post('finetuning', formData)
            .then(response => {
                console.log('Fine-tuning started:', response.data);
                setFineTuningStatus('Fine-tuning started successfully.'); // Update status
                setIsLoading(false);
            })
            .catch(error => {
                console.error('Error starting fine-tuning:', error);
                setFineTuningStatus('Error starting fine-tuning.'); // Update status
                setIsLoading(false);
            });
    };

    return (
        <Box sx={{ display: 'flex', flexDirection: 'column', minHeight: '100vh' }}>
            <Navbar />
            <Box component='main' sx={{ flexGrow: 1, padding: '24px' }}>
                <Typography variant='h4' sx={{ fontFamily: 'monospace', fontWeight: 600, mb: 4 }}>
                    Fine-Tune LLM
                </Typography>
                <Grid container spacing={4}>
                    <Grid item xs={12} md={6}>
                        <Paper sx={{ padding: 3 }}>
                            <Typography variant='h6' sx={{ fontFamily: 'monospace', fontWeight: 600, mb: 2 }}>
                                LLM Selection
                            </Typography>
                            <FormControl fullWidth sx={{ mb: 3 }}>
                                <InputLabel id="model-label">LLM Model</InputLabel>
                                <Select
                                    labelId="model-label"
                                    id="model"
                                    value={model}
                                    onChange={handleModelChange}
                                    label="LLM Model"
                                >
                                    <MenuItem value="meta-llama/Llama-2-7b-chat-hf">LLaMA 2 7B</MenuItem>
                                    <MenuItem value="meta-llama/Llama-2-13b-chat-hf">LLaMA 2 13B</MenuItem>
                                    <MenuItem value="meta-llama/Llama-2-70b-chat-hf">LLaMA 2 70B</MenuItem>
                                    <MenuItem value="Other">Other</MenuItem>
                                </Select>
                            </FormControl>
                            {model === 'Other' && (
                                <TextField
                                    fullWidth
                                    label="Custom Model"
                                    value={customModel}
                                    onChange={(e) => setCustomModel(e.target.value)}
                                    sx={{ mb: 3 }}
                                />
                            )}
                            <TextField
                                fullWidth
                                label="Name of the Fine-tuned Model"
                                value={finetunedModelName}
                                onChange={(e) => setFinetunedModelName(e.target.value)}
                                sx={{ mb: 3 }}
                            />
                        </Paper>
                    </Grid>

                    <Grid item xs={12} md={6}>
                        <Paper sx={{ padding: 3 }}>
                            <Typography variant='h6' sx={{ fontFamily: 'monospace', fontWeight: 600, mb: 2 }}>
                                Dataset Selection
                            </Typography>
                            <Grid container spacing={2}>
                                {allDatasets.map((dataset) => (
                                    <Grid item xs={12} key={dataset.id}>
                                        <Typography variant='subtitle1' sx={{ fontFamily: 'monospace', fontWeight: 600, mb: 1 }}>
                                            {dataset.title}
                                        </Typography>
                                        <FormGroup>
                                            {dataset.datasets.map((subDataset) => (
                                                <FormControlLabel
                                                    control={
                                                        <Checkbox
                                                            checked={selectedDatasets.includes(subDataset.fileUrl)}
                                                            onChange={handleDatasetChange}
                                                            name={subDataset.id}
                                                        />
                                                    }
                                                    label={subDataset.title}
                                                    key={subDataset.id}
                                                />
                                            ))}
                                        </FormGroup>
                                    </Grid>
                                ))}
                                <Grid item xs={12}>
                                    <Typography variant='subtitle1' sx={{ fontFamily: 'monospace', fontWeight: 600, mb: 1 }}>
                                        User Dataset
                                    </Typography>
                                    <Button variant="contained" component="label">
                                        Upload File
                                        <input type="file" hidden onChange={handleUserDatasetChange} />
                                    </Button>
                                    {userDataset && (
                                        <Typography variant='body2' sx={{ fontFamily: 'monospace', mt: 2 }}>
                                            {userDataset.name}
                                        </Typography>
                                    )}
                                    <Typography variant='body2' sx={{ fontFamily: 'monospace', mt: 2 }}>
                                        Note: Please upload a dataset in the following format: [placeholder for dataset format description].
                                    </Typography>
                                </Grid>
                            </Grid>
                        </Paper>
                    </Grid>

                    <Grid item xs={12}>
                        <Paper sx={{ padding: 3 }}>
                            <Typography variant='h6' sx={{ fontFamily: 'monospace', fontWeight: 600, mb: 2 }}>
                                Train/Test Split
                            </Typography>
                            <TextField
                                fullWidth
                                label="Number of Test Samples"
                                value={testSamples}
                                onChange={(e) => setTestSamples(e.target.value)}
                                sx={{ mb: 3 }}
                            />
                        </Paper>
                    </Grid>

                    <Grid item xs={12}>
                        <Paper sx={{ padding: 3 }}>
                            <Typography variant='h6' sx={{ fontFamily: 'monospace', fontWeight: 600, mb: 2 }}>
                                Hyperparameters
                            </Typography>
                            <Grid container spacing={2}>
                                <Grid item xs={12} sm={4}>
                                    <TextField
                                        fullWidth
                                        label="Lora Alpha"
                                        type="number"
                                        name="lora_alpha"
                                        value={hyperparameters.lora_alpha}
                                        onChange={handleHyperparameterChange}
                                        sx={{ mb: 3 }}
                                    />
                                </Grid>
                                <Grid item xs={12} sm={4}>
                                    <TextField
                                        fullWidth
                                        label="Lora Dropout"
                                        type="number"
                                        name="lora_dropout"
                                        value={hyperparameters.lora_dropout}
                                        onChange={handleHyperparameterChange}
                                        sx={{ mb: 3 }}
                                    />
                                </Grid>
                                <Grid item xs={12} sm={4}>
                                    <TextField
                                        fullWidth
                                        label="Lora R"
                                        type="number"
                                        name="lora_r"
                                        value={hyperparameters.lora_r}
                                        onChange={handleHyperparameterChange}
                                        sx={{ mb: 3 }}
                                    />
                                </Grid>
                                <Grid item xs={12} sm={4}>
                                    <TextField
                                        fullWidth
                                        label="Per Device Train Batch Size"
                                        type="number"
                                        name="per_device_train_batch_size"
                                        value={hyperparameters.per_device_train_batch_size}
                                        onChange={handleHyperparameterChange}
                                        sx={{ mb: 3 }}
                                    />
                                </Grid>
                                <Grid item xs={12} sm={4}>
                                    <TextField
                                        fullWidth
                                        label="Gradient Accumulation Steps"
                                        type="number"
                                        name="gradient_accumulation_steps"
                                        value={hyperparameters.gradient_accumulation_steps}
                                        onChange={handleHyperparameterChange}
                                        sx={{ mb: 3 }}
                                    />
                                </Grid>
                                <Grid item xs={12} sm={4}>
                                    <TextField
                                        fullWidth
                                        label="Optimizer"
                                        name="optim"
                                        value={hyperparameters.optim}
                                        onChange={handleHyperparameterChange}
                                        sx={{ mb: 3 }}
                                    />
                                </Grid>
                                <Grid item xs={12} sm={4}>
                                    <TextField
                                        fullWidth
                                        label="Save Steps"
                                        type="number"
                                        name="save_steps"
                                        value={hyperparameters.save_steps}
                                        onChange={handleHyperparameterChange}
                                        sx={{ mb: 3 }}
                                    />
                                </Grid>
                                <Grid item xs={12} sm={4}>
                                    <TextField
                                        fullWidth
                                        label="Logging Steps"
                                        type="number"
                                        name="logging_steps"
                                        value={hyperparameters.logging_steps}
                                        onChange={handleHyperparameterChange}
                                        sx={{ mb: 3 }}
                                    />
                                </Grid>
                                <Grid item xs={12} sm={4}>
                                    <TextField
                                        fullWidth
                                        label="Learning Rate"
                                        type="number"
                                        name="learning_rate"
                                        value={hyperparameters.learning_rate}
                                        onChange={handleHyperparameterChange}
                                        sx={{ mb: 3 }}
                                    />
                                </Grid>
                                <Grid item xs={12} sm={4}>
                                    <TextField
                                        fullWidth
                                        label="Max Grad Norm"
                                        type="number"
                                        name="max_grad_norm"
                                        value={hyperparameters.max_grad_norm}
                                        onChange={handleHyperparameterChange}
                                        sx={{ mb: 3 }}
                                    />
                                </Grid>
                                <Grid item xs={12} sm={4}>
                                    <TextField
                                        fullWidth
                                        label="Max Steps"
                                        type="number"
                                        name="max_steps"
                                        value={hyperparameters.max_steps}
                                        onChange={handleHyperparameterChange}
                                        sx={{ mb: 3 }}
                                    />
                                </Grid>
                                <Grid item xs={12} sm={4}>
                                    <TextField
                                        fullWidth
                                        label="Warmup Ratio"
                                        type="number"
                                        name="warmup_ratio"
                                        value={hyperparameters.warmup_ratio}
                                        onChange={handleHyperparameterChange}
                                        sx={{ mb: 3 }}
                                    />
                                </Grid>
                                <Grid item xs={12} sm={4}>
                                    <TextField
                                        fullWidth
                                        label="LR Scheduler Type"
                                        name="lr_scheduler_type"
                                        value={hyperparameters.lr_scheduler_type}
                                        onChange={handleHyperparameterChange}
                                        sx={{ mb: 3 }}
                                    />
                                </Grid>
                            </Grid>
                        </Paper>
                    </Grid>
                </Grid>

                <Box sx={{ display: 'flex', justifyContent: 'center', mt: 4 }}>
                    <Button variant="contained" color="primary" onClick={handleStartFineTuning} disabled={isLoading}>
                        {isLoading ? <CircularProgress size={24} /> : 'Start Fine-Tuning'}
                    </Button>
                </Box>
                {fineTuningStatus && (
                    <Typography variant="body2" sx={{ mt: 2, textAlign: 'center', fontFamily: 'monospace' }}>
                        {fineTuningStatus}
                    </Typography>
                )}
            </Box>
            <Footer />
        </Box>
    );
};

export default FineTuningPage;
